import axiosInstance from "../axiosConfig";
import { useFormik } from "formik";
import { useCookies } from "react-cookie";
import { useNavigate } from "react-router-dom";

export function AdminLogin() {
    const navigate = useNavigate();
    const [cookies, setCookie] = useCookies(['admin-id']);

    const formik = useFormik({
        initialValues: {
            UserId: '',
            Password: ''
        },
        onSubmit: (formValues) => {
            axiosInstance.get('/get-admin')
                .then(response => {
                    const admins = response.data;

                    if (!Array.isArray(admins) || admins.length === 0) {
                        alert("No admins found");
                        return;
                    }

                    const match = admins.find(admin =>
                        admin.UserId === formValues.UserId &&
                        admin.Password === formValues.Password
                    );

                    if (match) {
                        setCookie('admin-id', match.UserId);
                        navigate('/admin-dashboard');
                        window.location.reload();
                    } else {
                        alert("Invalid Admin ID or Password");
                        navigate('/admin-error');
                    }
                })
                .catch(error => {
                    console.error("Server error:", error);
                    alert("Server error. Please try again later.");
                });
        }
    });

    return (
        <div className="d-flex justify-content-center align-items-center" style={{ height: '60vh' }}>
            <form className="w-25" onSubmit={formik.handleSubmit}>
                <div className="text-center fs-4 mb-3">👤 Admin Login</div>
                <dl>
                    <dt>Admin ID</dt>
                    <dd>
                        <input
                            type="text"
                            name="UserId"
                            onChange={formik.handleChange}
                            className="form-control"
                            autoComplete="username"
                            required
                        />
                    </dd>
                    <dt>Password</dt>
                    <dd>
                        <input
                            type="password"
                            name="Password"
                            onChange={formik.handleChange}
                            className="form-control"
                            autoComplete="current-password"
                            required
                        />
                    </dd>
                </dl>
                <button className="btn btn-danger w-100">Login</button>
            </form>
        </div>
    );
}
